#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int A[N], B[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        for (int i = 0; i < N; i++) {
            scanf("%d", &B[i]);
        }
        long long swagness = 0;
        for (int mask = 1; mask < (1 << N); mask++) {
            int maxA = 0, maxB = 0;
            for (int i = 0; i < N; i++) {
                if ((mask & (1 << i)) != 0) {
                    maxA = (maxA > A[i]) ? maxA : A[i];
                    maxB = (maxB > B[i]) ? maxB : B[i];
                }
            }
            swagness = (swagness + (long long)maxA * maxB) % MOD;
        }
        printf("%lld\n", swagness);
    }
    return 0;
}

