import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] A = new int[N];
            int[] B = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            for (int i = 0; i < N; i++) {
                B[i] = sc.nextInt();
            }
            long swagness = 0;
            for (int mask = 1; mask < (1 << N); mask++) {
                int maxA = 0, maxB = 0;
                for (int i = 0; i < N; i++) {
                    if ((mask & (1 << i)) != 0) {
                        maxA = Math.max(maxA, A[i]);
                        maxB = Math.max(maxB, B[i]);
                    }
                }
                swagness = (swagness + (long)maxA * maxB) % 1000000007;
            }
            System.out.println(swagness);
        }
    }
}

