const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const MOD = 1000000007;

function nextInt() {
    return parseInt(input[idx++]);
}

function nextIntArray() {
    return input[idx++].split(' ').map(x => parseInt(x));
}

let T = nextInt();
while (T-- > 0) {
    let N = nextInt();
    let A = nextIntArray();
    let B = nextIntArray();
    let swagness = 0;
    for (let mask = 1; mask < (1 << N); mask++) {
        let maxA = 0;
        let maxB = 0;
        for (let i = 0; i < N; i++) {
            if ((mask & (1 << i)) != 0) {
                maxA = Math.max(maxA, A[i]);
                maxB = Math.max(maxB, B[i]);
            }
        }
        swagness = (swagness + maxA * maxB) % MOD;
    }
    console.log(swagness);
}

